What does this program print?

```cpp
#include <iostream>

struct A {
    int x_;
    A(int x) : x_(x) {}
};

struct B : virtual public A {
    B(int x) : A(x) {}
};

struct C : virtual public A {
    C(int x) : A(x) {}
};

struct D : public B, public C {
    D(int x) : A(x), B(x), C(x) {}
};

int main() {
    D d{7};
    std::cout << d.x_ << "\n";
}
```
